   285→import { ThemedText } from '@/components/themed-text'
   286→import { ThemedView } from '@/components/themed-view'
   287→import { useSignIn } from '@clerk/expo'
   288→import { type Href, Link, useRouter } from 'expo-router'
   289→import React from 'react'
   290→import { Pressable, StyleSheet, TextInput, View } from 'react-native'
   291→
   292→export default function Page() {
   293→  const { signIn, errors, fetchStatus } = useSignIn()
   294→  const router = useRouter()
   295→
   296→  const [emailAddress, setEmailAddress] = React.useState('')
   297→  const [password, setPassword] = React.useState('')
   298→  const [code, setCode] = React.useState('')
   299→
   300→  const handleSubmit = async () => {
   301→    const { error } = await signIn.password({
   302→      emailAddress,
   303→      password,
   304→    })
   305→    if (error) {
   306→      console.error(JSON.stringify(error, null, 2))
   307→      return
   308→    }
   309→
   310→    if (signIn.status === 'complete') {
   311→      await signIn.finalize({
   312→        navigate: ({ session, decorateUrl }) => {
   313→          if (session?.currentTask) {
   314→            // Handle pending session tasks
   315→            // See https://clerk.com/docs/guides/development/custom-flows/authentication/session-tasks
   316→            console.log(session?.currentTask)
   317→            return
   318→          }
   319→
   320→          const url = decorateUrl('/')
   321→          if (url.startsWith('http')) {
   322→            window.location.href = url
   323→          } else {
   324→            router.push(url as Href)
   325→          }
   326→        },
   327→      })
   328→    } else if (signIn.status === 'needs_second_factor') {
   329→      // See https://clerk.com/docs/guides/development/custom-flows/authentication/multi-factor-authentication
   330→    } else if (signIn.status === 'needs_client_trust') {
   331→      // For other second factor strategies,
   332→      // see https://clerk.com/docs/guides/development/custom-flows/authentication/client-trust
   333→      const emailCodeFactor = signIn.supportedSecondFactors.find(
   334→        (factor) => factor.strategy === 'email_code',
   335→      )
   336→
   337→      if (emailCodeFactor) {
   338→        await signIn.mfa.sendEmailCode()
   339→      }
   340→    } else {
   341→      // Check why the sign-in is not complete
   342→      console.error('Sign-in attempt not complete:', signIn)
   343→    }
   344→  }
   345→
   346→  const handleVerify = async () => {
   347→    await signIn.mfa.verifyEmailCode({ code })
   348→
   349→    if (signIn.status === 'complete') {
   350→      await signIn.finalize({
   351→        navigate: ({ session, decorateUrl }) => {
   352→          if (session?.currentTask) {
   353→            // Handle pending session tasks
   354→            // See https://clerk.com/docs/guides/development/custom-flows/authentication/session-tasks
   355→            console.log(session?.currentTask)
   356→            return
   357→          }
   358→
   359→          const url = decorateUrl('/')
   360→          if (url.startsWith('http')) {
   361→            window.location.href = url
   362→          } else {
   363→            router.push(url as Href)
   364→          }
   365→        },
   366→      })
   367→    } else {
   368→      // Check why the sign-in is not complete
   369→      console.error('Sign-in attempt not complete:', signIn)
   370→    }
   371→  }
   372→
   373→  if (signIn.status === 'needs_client_trust') {
   374→    return (
   375→      <ThemedView style={styles.container}>
   376→        <ThemedText type="title" style={[styles.title, { fontSize: 24, fontWeight: 'bold' }]}>
   377→          Verify your account
   378→        </ThemedText>
   379→        <TextInput
   380→          style={styles.input}
   381→          value={code}
   382→          placeholder="Enter your verification code"
   383→          placeholderTextColor="#666666"
   384→          onChangeText={(code) => setCode(code)}
   385→          keyboardType="numeric"
   386→        />
   387→        {errors.fields.code && (
   388→          <ThemedText style={styles.error}>{errors.fields.code.message}</ThemedText>
   389→        )}
   390→        <Pressable
   391→          style={({ pressed }) => [
   392→            styles.button,
   393→            fetchStatus === 'fetching' && styles.buttonDisabled,
   394→            pressed && styles.buttonPressed,
   395→          ]}
   396→          onPress={handleVerify}
   397→          disabled={fetchStatus === 'fetching'}
   398→        >
   399→          <ThemedText style={styles.buttonText}>Verify</ThemedText>
   400→        </Pressable>
   401→        <Pressable
   402→          style={({ pressed }) => [styles.secondaryButton, pressed && styles.buttonPressed]}
   403→          onPress={() => signIn.mfa.sendEmailCode()}
   404→        >
   405→          <ThemedText style={styles.secondaryButtonText}>I need a new code</ThemedText>
   406→        </Pressable>
   407→        <Pressable
   408→          style={({ pressed }) => [styles.secondaryButton, pressed && styles.buttonPressed]}
   409→          onPress={() => signIn.reset()}
   410→        >
   411→          <ThemedText style={styles.secondaryButtonText}>Start over</ThemedText>
   412→        </Pressable>
   413→      </ThemedView>
   414→    )
   415→  }
   416→
   417→  return (
   418→    <ThemedView style={styles.container}>
   419→      <ThemedText type="title" style={styles.title}>
   420→        Sign in
   421→      </ThemedText>
   422→
   423→      <ThemedText style={styles.label}>Email address</ThemedText>
   424→      <TextInput
   425→        style={styles.input}
   426→        autoCapitalize="none"
   427→        value={emailAddress}
   428→        placeholder="Enter email"
   429→        placeholderTextColor="#666666"
   430→        onChangeText={(emailAddress) => setEmailAddress(emailAddress)}
   431→        keyboardType="email-address"
   432→      />
   433→      {errors.fields.identifier && (
   434→        <ThemedText style={styles.error}>{errors.fields.identifier.message}</ThemedText>
   435→      )}
   436→      <ThemedText style={styles.label}>Password</ThemedText>
   437→      <TextInput
   438→        style={styles.input}
   439→        value={password}
   440→        placeholder="Enter password"
   441→        placeholderTextColor="#666666"
   442→        secureTextEntry={true}
   443→        onChangeText={(password) => setPassword(password)}
