   430→import { ThemedText } from '@/components/themed-text'
   431→import { ThemedView } from '@/components/themed-view'
   432→import { useAuth, useSignUp } from '@clerk/expo'
   433→import { type Href, Link, useRouter } from 'expo-router'
   434→import React from 'react'
   435→import { Pressable, StyleSheet, TextInput, View } from 'react-native'
   436→
   437→export default function Page() {
   438→  const { signUp, errors, fetchStatus } = useSignUp()
   439→  const { isSignedIn } = useAuth()
   440→  const router = useRouter()
   441→
   442→  const [emailAddress, setEmailAddress] = React.useState('')
   443→  const [password, setPassword] = React.useState('')
   444→  const [code, setCode] = React.useState('')
   445→
   446→  const handleSubmit = async () => {
   447→    const { error } = await signUp.password({
   448→      emailAddress,
   449→      password,
   450→    })
   451→    if (error) {
   452→      console.error(JSON.stringify(error, null, 2))
   453→      return
   454→    }
   455→
   456→    if (!error) await signUp.verifications.sendEmailCode()
   457→  }
   458→
   459→  const handleVerify = async () => {
   460→    await signUp.verifications.verifyEmailCode({
   461→      code,
   462→    })
   463→    if (signUp.status === 'complete') {
   464→      await signUp.finalize({
   465→        // Redirect the user to the home page after signing up
   466→        navigate: ({ session, decorateUrl }) => {
   467→          if (session?.currentTask) {
   468→            // Handle pending session tasks
   469→            // See https://clerk.com/docs/guides/development/custom-flows/authentication/session-tasks
   470→            console.log(session?.currentTask)
   471→            return
   472→          }
   473→
   474→          const url = decorateUrl('/')
   475→          if (url.startsWith('http')) {
   476→            window.location.href = url
   477→          } else {
   478→            router.push(url as Href)
   479→          }
   480→        },
   481→      })
   482→    } else {
   483→      // Check why the sign-up is not complete
   484→      console.error('Sign-up attempt not complete:', signUp)
   485→    }
   486→  }
   487→
   488→  if (signUp.status === 'complete' || isSignedIn) {
   489→    return null
   490→  }
   491→
   492→  if (
   493→    signUp.status === 'missing_requirements' &&
   494→    signUp.unverifiedFields.includes('email_address') &&
   495→    signUp.missingFields.length === 0
   496→  ) {
   497→    return (
   498→      <ThemedView style={styles.container}>
   499→        <ThemedText type="title" style={styles.title}>
   500→          Verify your account
   501→        </ThemedText>
   502→        <TextInput
   503→          style={styles.input}
   504→          value={code}
   505→          placeholder="Enter your verification code"
   506→          placeholderTextColor="#666666"
   507→          onChangeText={(code) => setCode(code)}
   508→          keyboardType="numeric"
   509→        />
   510→        {errors.fields.code && (
   511→          <ThemedText style={styles.error}>{errors.fields.code.message}</ThemedText>
   512→        )}
   513→        <Pressable
