    13→export function getRelativeTime(timestamp: number): string {
    14→  const now = Date.now();
    15→  const diff = Math.floor((now - timestamp) / 1000);
    16→
    17→  if (diff < 5) return "just now";
    18→  if (diff < 60) return `${diff}s ago`;
    19→  if (diff < 3600) {
    20→    const mins = Math.floor(diff / 60);
    21→    return `${mins}m ago`;
    22→  }
    23→  if (diff < 86400) {
    24→    const hours = Math.floor(diff / 3600);
    25→    return `${hours}h ago`;
    26→  }
    27→  const days = Math.floor(diff / 86400);
    28→  return `${days}d ago`;
    29→}
    30→
    31→export function formatDateTime(timestamp: number): string {
    32→  const date = new Date(timestamp);
    33→  const months = [
    34→    "Jan", "Feb", "Mar", "Apr", "May", "Jun",
    35→    "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
    36→  ];
    37→  const month = months[date.getMonth()];
    38→  const day = date.getDate();
    39→  const year = date.getFullYear();
    40→  const hours = date.getHours();
    41→  const minutes = date.getMinutes().toString().padStart(2, "0");
    42→  const ampm = hours >= 12 ? "PM" : "AM";
    43→  const h = hours % 12 || 12;
    44→  return `${month} ${day}, ${year} at ${h}:${minutes} ${ampm}`;
    45→}
