    44→function formatTimer(seconds: number): string {
    45→  const h = Math.floor(seconds / 3600);
    46→  const m = Math.floor((seconds % 3600) / 60);
    47→  const s = seconds % 60;
    48→  const pad = (n: number) => n.toString().padStart(2, "0");
    49→  if (h > 0) return `${pad(h)}:${pad(m)}:${pad(s)}`;
    50→  return `${pad(m)}:${pad(s)}`;
    51→}
    52→
    53→function calcDholta(
    54→  totalWeight: number,
    55→  kgPerCrate: number,
    56→  deductionPerCrateG: number,
    57→  fullCratesOnly: boolean
    58→): { totalCrates: number; totalDeductionKg: number; netWeight: number } {
    59→  const rawCrates = totalWeight / kgPerCrate;
    60→  const totalCrates = fullCratesOnly ? Math.floor(rawCrates) : rawCrates;
    61→  const totalDeductionKg = (totalCrates * deductionPerCrateG) / 1000;
    62→  const netWeight = totalWeight - totalDeductionKg;
    63→  return { totalCrates, totalDeductionKg, netWeight };
    64→}
