import { router, useFocusEffect } from "expo-router";
import { Ionicons, Feather, MaterialCommunityIcons } from "@expo/vector-icons";
import * as Haptics from "expo-haptics";
import Animated, { FadeInDown, FadeIn } from "react-native-reanimated";
import { useTheme } from "@/lib/useTheme";
import { useSettings } from "@/lib/SettingsContext";
import { loadSales, deleteSale, loadDrafts } from "@/lib/storage";
import { formatWeight, formatDateTime } from "@/lib/utils";
import type { SaleRecord, DraftSession } from "@/lib/types";

function SaleCard({
  sale,
  index,
  theme,
  onDelete,
  t,
}: {
  sale: SaleRecord;
  index: number;
  theme: ReturnType<typeof useTheme>;
  onDelete: (id: string) => void;
  t: ReturnType<typeof useSettings>["t"];
}) {
  const { dholta } = sale;

  const handleDelete = () => {
    if (Platform.OS === "web") {
      onDelete(sale.id);
    } else {
      Alert.alert(t.homeDeleteTitle, t.homeDeleteMessage, [
        { text: t.cancel, style: "cancel" },
        {
          text: t.delete,
          style: "destructive",
          onPress: () => onDelete(sale.id),
        },
      ]);
    }
  };

  const handlePress = () => {
    router.push({ pathname: "/sale/[id]", params: { id: sale.id } });
  };

  return (
    <Animated.View
      entering={
        Platform.OS !== "web"
          ? FadeInDown.delay(index * 50).springify()
          : undefined
      }
    >
      <Pressable
        onPress={handlePress}
        style={({ pressed }) => [
          styles.card,
          {
            backgroundColor: theme.surface,
            borderColor: theme.borderLight,
            ...(Platform.OS !== "web" ? { shadowColor: theme.cardShadow } : {}),
            opacity: pressed ? 0.92 : 1,
          },
        ]}
        testID={`sale-card-${index}`}
      >
        <View style={styles.cardTop}>
          <View style={styles.cardDateRow}>
            <View
              style={[styles.dateBadge, { backgroundColor: theme.accentLight }]}
            >
              <Feather name="calendar" size={13} color={theme.accent} />
            </View>
            <Text
              style={[
                styles.cardDate,
                {
                  color: theme.textSecondary,
                  fontFamily: "Outfit_400Regular",
                },
              ]}
            >
              {formatDateTime(sale.createdAt)}
            </Text>
          </View>
          <Pressable
            onPress={handleDelete}
            hitSlop={16}
            style={({ pressed }) => [
              styles.deleteBtn,
              {
                backgroundColor: theme.dangerLight,
                opacity: pressed ? 0.6 : 1,
              },
            ]}
          >
            <Feather name="trash-2" size={14} color={theme.danger} />
          </Pressable>
        </View>

        <View style={styles.cardStats}>
          <View style={styles.statBlock}>
            <Text
              style={[
                styles.statValue,
                { color: theme.accent, fontFamily: "Outfit_700Bold" },
              ]}
            >
              {formatWeight(sale.totalWeightKg)}
            </Text>
            <Text
              style={[
                styles.statLabel,
                { color: theme.textTertiary, fontFamily: "Outfit_500Medium" },
              ]}
            >
              {t.grossKg}
            </Text>
          </View>
          <View style={[styles.statSep, { backgroundColor: theme.border }]} />
          <View style={styles.statBlock}>
            <Text
              style={[
                styles.statValue,
                { color: theme.warm, fontFamily: "Outfit_700Bold" },
              ]}
            >
              {sale.totalPcs}
            </Text>
            <Text
              style={[
                styles.statLabel,
                { color: theme.textTertiary, fontFamily: "Outfit_500Medium" },
              ]}
            >
              {t.birds}
            </Text>
          </View>
          <View style={[styles.statSep, { backgroundColor: theme.border }]} />
          <View style={styles.statBlock}>
            <Text
              style={[
                styles.statValue,
                { color: theme.text, fontFamily: "Outfit_700Bold" },
              ]}
            >
              {dholta
                ? formatWeight(dholta.net_weight)
                : formatWeight(sale.averageWeightKg)}
            </Text>
            <Text
              style={[
                styles.statLabel,
                { color: theme.textTertiary, fontFamily: "Outfit_500Medium" },
              ]}
            >
              {dholta ? t.netKg : t.avgKg}
            </Text>
          </View>
        </View>

        {dholta ? (
          <View
            style={[
              styles.dholtaStrip,
              {
                backgroundColor: theme.accentLight,
                borderTopColor: theme.borderLight,
              },
            ]}
          >
            <View style={styles.dholtaLeft}>
              <Feather name="minus-circle" size={13} color={theme.accent} />
              <Text
                style={[
                  styles.dholtaDeduction,
                  {
                    color: theme.textSecondary,
                    fontFamily: "Outfit_400Regular",
                  },
                ]}
              >
                {t.dholta}{" "}
                <Text
                  style={{
                    fontFamily: "Outfit_600SemiBold",
                    color: theme.danger,
                  }}
                >
                  -{formatWeight(dholta.total_deduction_kg)} KG
                </Text>
                {"  "}
                <Text style={{ color: theme.textTertiary }}>
                  (
                  {dholta.total_crates % 1 === 0
                    ? dholta.total_crates
                    : dholta.total_crates.toFixed(2)}{" "}
                  crates)
                </Text>
              </Text>
            </View>
            <Text
              style={[
                styles.dholtaAmount,
                { color: theme.accent, fontFamily: "Outfit_700Bold" },
              ]}
            >
              Tk{" "}
              {dholta.final_amount.toLocaleString("en-PK", {
                maximumFractionDigits: 0,
              })}
            </Text>
          </View>
        ) : (
          <View
            style={[styles.cardBottom, { borderTopColor: theme.borderLight }]}
          >
            <View style={styles.rowInfo}>
              <Feather name="layers" size={12} color={theme.textTertiary} />
              <Text
                style={[
                  styles.rowInfoText,
                  {
                    color: theme.textTertiary,
                    fontFamily: "Outfit_400Regular",
                  },
                ]}
              >
                {t.weighings(sale.rows.length)}
              </Text>
            </View>
            <View style={styles.viewDetailRow}>
              <Text
                style={[
                  styles.viewDetailText,
                  { color: theme.accent, fontFamily: "Outfit_500Medium" },
                ]}
              >
                {t.viewDetail}
              </Text>
              <Feather name="chevron-right" size={13} color={theme.accent} />
            </View>
          </View>
        )}
      </Pressable>
    </Animated.View>
  );
}

export default function HomeScreen() {
  const theme = useTheme();
  const insets = useSafeAreaInsets();
  const { t } = useSettings();
  const [sales, setSales] = useState<SaleRecord[]>([]);
  const [drafts, setDrafts] = useState<DraftSession[]>([]);
  const [loading, setLoading] = useState(true);

  useFocusEffect(
    useCallback(() => {
      Promise.all([loadSales(), loadDrafts()]).then(([salesData, draftsData]) => {
        setSales(salesData);
        setDrafts(draftsData);
        setLoading(false);
      });
    }, [])
  );

  const handleDelete = async (id: string) => {
    await deleteSale(id);
    setSales((prev) => prev.filter((s) => s.id !== id));
    if (Platform.OS !== "web") {
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
    }
  };

  const handleNewMeasurement = () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }
    router.push("/measurement");
  };

  const handleOpenDrafts = () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    router.push("/drafts");
  };

  const handleOpenSettings = () => {
    if (Platform.OS !== "web") {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    router.push("/settings");
  };

  const webTopInset = Platform.OS === "web" ? 67 : 0;
  const webBottomInset = Platform.OS === "web" ? 34 : 0;

  return (
    <View style={[styles.container, { backgroundColor: theme.background }]}>
      <View
        style={[
          styles.header,
          {
            paddingTop: insets.top + webTopInset + 12,
            backgroundColor: theme.surface,
            borderBottomColor: theme.border,
          },
        ]}
      >
        <View style={styles.headerLeft}>
          <View
            style={[styles.logoBadge, { backgroundColor: theme.accentLight }]}
          >
            <MaterialCommunityIcons
              name="bird"
              size={22}
              color={theme.accent}
            />
          </View>
          <View>
            <Text
              style={[
                styles.headerTitle,
                { color: theme.text, fontFamily: "Outfit_700Bold" },
              ]}
            >
              {t.appName}
            </Text>
            <Text
              style={[
                styles.headerSub,
                {
                  color: theme.textTertiary,
                  fontFamily: "Outfit_400Regular",
                },
              ]}
            >
              {sales.length > 0
                ? t.homeSalesRecorded(sales.length)
                : t.homeReadyToWeigh}
            </Text>
          </View>
        </View>
        <Pressable
          onPress={handleOpenSettings}
          hitSlop={12}
          style={({ pressed }) => [
            styles.settingsBtn,
            { backgroundColor: theme.borderLight, opacity: pressed ? 0.6 : 1 },
          ]}
        >
          <Ionicons name="settings-outline" size={20} color={theme.text} />
        </Pressable>
      </View>

      {drafts.length > 0 && (
        <Pressable
          onPress={handleOpenDrafts}
          style={({ pressed }) => [
            styles.draftBanner,
            {
              backgroundColor: theme.warmLight,
              borderColor: theme.warm,
              opacity: pressed ? 0.85 : 1,
            },
          ]}
        >
          <View style={styles.draftBannerLeft}>
            <View
              style={[
                styles.draftBannerIcon,
                { backgroundColor: theme.warm },
              ]}
            >
              <MaterialCommunityIcons
                name="progress-clock"
                size={15}
                color="#FFF"
              />
            </View>
            <Text
              style={[
                styles.draftBannerText,
                { color: theme.warm, fontFamily: "Outfit_600SemiBold" },
              ]}
            >
              {t.homeDraftBanner(drafts.length)}
            </Text>
          </View>
          <Feather name="chevron-right" size={16} color={theme.warm} />
        </Pressable>
      )}

      {loading ? (
        <View style={styles.emptyWrap}>
          <Text
            style={[
              styles.emptyMsg,
              { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
            ]}
          >
            {t.loading}
          </Text>
        </View>
      ) : sales.length === 0 ? (
        <Animated.View
          style={styles.emptyWrap}
          entering={Platform.OS !== "web" ? FadeIn.delay(200) : undefined}
        >
          <View
            style={[styles.emptyIcon, { backgroundColor: theme.accentLight }]}
          >
            <MaterialCommunityIcons
              name="scale"
              size={44}
              color={theme.accent}
            />
          </View>
          <Text
            style={[
              styles.emptyTitle,
              { color: theme.text, fontFamily: "Outfit_600SemiBold" },
            ]}
          >
            {t.homeNoSales}
          </Text>
          <Text
            style={[
              styles.emptyMsg,
              { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
            ]}
          >
            {t.homeNoSalesHint}
          </Text>
        </Animated.View>
      ) : (
        <FlatList
          data={sales}
          keyExtractor={(item) => item.id}
          renderItem={({ item, index }) => (
            <SaleCard
              sale={item}
              index={index}
              theme={theme}
              onDelete={handleDelete}
              t={t}
            />
          )}
          contentContainerStyle={{
            padding: 16,
            paddingBottom: insets.bottom + webBottomInset + 100,
          }}
          showsVerticalScrollIndicator={false}
          scrollEnabled={!!sales.length}
        />
      )}

      <Pressable
        onPress={handleNewMeasurement}
        style={({ pressed }) => [
          styles.fab,
          {
            backgroundColor: theme.accent,
            bottom: insets.bottom + webBottomInset + 24,
            transform: [{ scale: pressed ? 0.9 : 1 }],
          },
        ]}
      >
        <Ionicons name="add" size={30} color="#FFFFFF" />
      </Pressable>
    </View>
  );
}

