              color={theme.warm}
            />
          </View>
          <View style={styles.cardInfo}>
            <Text
              style={[
                styles.cardTitle,
                { color: theme.text, fontFamily: "Outfit_700Bold" },
              ]}
            >
              {formatWeight(draft.totalWeightKg)}{" "}
              <Text style={[styles.cardUnit, { color: theme.textTertiary }]}>
                KG
              </Text>
            </Text>
            <View style={styles.cardMeta}>
