                {draft.rows.length} row{draft.rows.length !== 1 ? "s" : ""}
              </Text>
              <View
                style={[styles.dot, { backgroundColor: theme.textTertiary }]}
              />
              <Text
                style={[
                  styles.cardMetaText,
                  { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
