}

function DholtaRow({
  label,
  value,
  theme,
  isNegative,
  isHighlight,
}: {
  label: string;
  value: string;
  theme: ReturnType<typeof useTheme>;
  isNegative?: boolean;
  isHighlight?: boolean;
}) {
  const valueColor = isNegative
    ? theme.danger
    : isHighlight
    ? theme.success
    : theme.text;
  return (
    <View style={styles.dholtaRow}>
      <Text
        style={[
          styles.dholtaRowLabel,
          { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
        ]}
