          style={[
            styles.modalHeader,
            {
              backgroundColor: theme.surface,
              borderBottomColor: theme.border,
              paddingTop: insets.top + (Platform.OS === "web" ? 67 : 0) + 12,
            },
          ]}
        >
          <Pressable
            onPress={onCancel}
            hitSlop={16}
            style={({ pressed }) => [
              styles.modalCloseBtn,
              {
                backgroundColor: theme.borderLight,
                opacity: pressed ? 0.6 : 1,
