export interface RowEditEntry {
  id: string;
  timestamp: number;
  previousWeightKg: number;
  previousPcs: number;
  newWeightKg: number;
  newPcs: number;
}

export interface MeasurementRow {
  id: string;
  weightKg: number;
  pcs: number;
  timestamp: number;
  editHistory?: RowEditEntry[];
}

export interface SaleRecord {
  id: string;
  totalWeightKg: number;
  totalWeightGrams: number;
  totalPcs: number;
  averageWeightKg: number;
  averageWeightGrams: number;
  rows: MeasurementRow[];
  cullRows?: MeasurementRow[];
  createdAt: number;
  dholta?: DholtaDetails;
  receivedAmount?: number;
}

export interface DholtaDetails {
  gross_weight: number;
  kg_per_crate: number;
  deduction_per_crate_g: number;
  full_crates_only: boolean;
  total_crates: number;
  total_deduction_kg: number;
  cull_weight_kg: number;
  net_weight: number;
  price_per_kg: number;
  final_amount: number;
}

export interface DraftSession {
  id: string;
  rows: MeasurementRow[];
  mainRows?: MeasurementRow[];
  phase?: "main" | "cull";
  createdAt: number;
  updatedAt: number;
  totalWeightKg: number;
  totalPcs: number;
}

import React, { useState, useEffect, useRef, useCallback } from "react";
import {
  View,
  Text,
  StyleSheet,
  TextInput,
  Pressable,
  FlatList,
  Platform,
  Alert,
  Keyboard,
  Modal,
  ScrollView,
  ActivityIndicator,
} from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { router, useLocalSearchParams } from "expo-router";
import { Ionicons, Feather, MaterialCommunityIcons } from "@expo/vector-icons";
import * as Haptics from "expo-haptics";
import * as Crypto from "expo-crypto";
import Animated, { FadeInDown, FadeIn } from "react-native-reanimated";
import { useTheme } from "@/lib/useTheme";
import { useSettings } from "@/lib/SettingsContext";
import { formatWeight, getRelativeTime } from "@/lib/utils";
import {
  saveSale,
  loadLastPricePerKg,
  saveLastPricePerKg,
  loadLastKgPerCrate,
  saveLastKgPerCrate,
  loadLastDeductionG,
  saveLastDeductionG,
  loadDraft,
  saveDraft,
  deleteDraft,
} from "@/lib/storage";
import { EditRowModal } from "@/components/EditRowModal";
import type {
  MeasurementRow,
  SaleRecord,
  DholtaDetails,
  DraftSession,
} from "@/lib/types";

function formatTimer(seconds: number): string {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = seconds % 60;
  const pad = (n: number) => n.toString().padStart(2, "0");
  if (h > 0) return `${pad(h)}:${pad(m)}:${pad(s)}`;
  return `${pad(m)}:${pad(s)}`;
}

function calcDholta(
  totalWeight: number,
  kgPerCrate: number,
  deductionPerCrateG: number,
  fullCratesOnly: boolean
): { totalCrates: number; totalDeductionKg: number; netWeight: number } {
  const rawCrates = totalWeight / kgPerCrate;
  const totalCrates = fullCratesOnly ? Math.floor(rawCrates) : rawCrates;
  const totalDeductionKg = (totalCrates * deductionPerCrateG) / 1000;
  const netWeight = totalWeight - totalDeductionKg;
  return { totalCrates, totalDeductionKg, netWeight };
}

function RowItem({
  row,
  rowNumber,
  theme,
  onEdit,
}: {
  row: MeasurementRow;
  rowNumber: number;
  theme: ReturnType<typeof useTheme>;
  onEdit: (row: MeasurementRow) => void;
}) {
  const { t } = useSettings();
  const [timeAgo, setTimeAgo] = useState(getRelativeTime(row.timestamp));
  const lastEdit = row.editHistory?.[0];
  const [editAgo, setEditAgo] = useState(
    lastEdit ? getRelativeTime(lastEdit.timestamp) : ""
  );

  useEffect(() => {
    const interval = setInterval(() => {
      setTimeAgo(getRelativeTime(row.timestamp));
      if (lastEdit) setEditAgo(getRelativeTime(lastEdit.timestamp));
    }, 5000);
    return () => clearInterval(interval);
  }, [row.timestamp, lastEdit]);

  return (
    <Animated.View
      entering={
        Platform.OS !== "web" ? FadeInDown.springify().damping(18) : undefined
      }
    >
      <View
        style={[
          styles.rowCard,
          { backgroundColor: theme.surface, borderColor: theme.borderLight },
        ]}
      >
        <View style={[styles.rowNum, { backgroundColor: theme.accentLight }]}>
          <Text
            style={[
              styles.rowNumText,
              { color: theme.accent, fontFamily: "Outfit_700Bold" },
            ]}
          >
            {rowNumber}
          </Text>
        </View>

        <View style={styles.rowInfo}>
          <Text
            style={[
              styles.rowWeight,
              { color: theme.text, fontFamily: "Outfit_700Bold" },
            ]}
          >
            {formatWeight(row.weightKg)}
            <Text style={{ fontSize: 13, fontFamily: "Outfit_500Medium" }}>
              {" "}
              KG
            </Text>
          </Text>
          <View style={styles.rowMeta}>
            <Text
              style={[
                styles.rowTimeText,
                { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
              ]}
            >
              {timeAgo}
            </Text>
            {lastEdit && (
              <>
                <View
                  style={[
                    styles.metaDot,
                    { backgroundColor: theme.textTertiary },
                  ]}
                />
                <Text
                  style={[
                    styles.editedText,
                    { color: theme.accent, fontFamily: "Outfit_400Regular" },
                  ]}
                >
                  {t.edited} {editAgo}
                </Text>
              </>
            )}
          </View>
        </View>

        <View
          style={[styles.rowPcsBadge, { backgroundColor: theme.warmLight }]}
        >
          <MaterialCommunityIcons name="bird" size={13} color={theme.warm} />
          <Text
            style={[
              styles.rowPcsText,
              { color: theme.warm, fontFamily: "Outfit_600SemiBold" },
            ]}
          >
            {row.pcs}
          </Text>
        </View>

        <Pressable
          onPress={() => onEdit(row)}
          hitSlop={8}
          style={({ pressed }) => [
            styles.rowEditBtn,
            {
              backgroundColor: theme.accentLight,
              opacity: pressed ? 0.6 : 1,
            },
          ]}
          testID={`edit-row-${rowNumber}`}
        >
          <Feather name="edit-2" size={13} color={theme.accent} />
        </Pressable>
      </View>
    </Animated.View>
  );
}

function SummaryRow({
  label,
  value,
  theme,
  isNegative,
  isHighlight,
}: {
  label: string;
  value: string;
  theme: ReturnType<typeof useTheme>;
  isNegative?: boolean;
  isHighlight?: boolean;
}) {
  const valueColor = isNegative
    ? theme.danger
    : isHighlight
    ? theme.success
    : theme.text;
  return (
    <View style={styles.summaryRow}>
      <Text
        style={[
          styles.summaryLabel,
          { color: theme.textTertiary, fontFamily: "Outfit_400Regular" },
        ]}
      >
        {label}
      </Text>
      <Text
        style={[
          styles.summaryValue,
          { color: valueColor, fontFamily: "Outfit_600SemiBold" },
        ]}
      >
        {value}
      </Text>
    </View>
  );
}

function CullDialog({
  visible,
  theme,
  onYes,
  onNo,
}: {
  visible: boolean;
  theme: ReturnType<typeof useTheme>;
  onYes: () => void;
  onNo: () => void;
}) {
  const { t } = useSettings();
  return (
    <Modal
      visible={visible}
      transparent
      animationType="fade"
      onRequestClose={onNo}
    >
      <View style={styles.cullOverlay}>
        <Animated.View
          entering={Platform.OS !== "web" ? FadeIn.duration(180) : undefined}
          style={[
            styles.cullCard,
            {
              backgroundColor: theme.surface,
              borderColor: theme.borderLight,
            },
          ]}
        >
          <View
            style={[
              styles.cullIconWrap,
              { backgroundColor: theme.warmLight },
            ]}
          >
            <MaterialCommunityIcons
              name="bird"
              size={30}
              color={theme.warm}
            />
          </View>
          <Text
            style={[
              styles.cullTitle,
              { color: theme.text, fontFamily: "Outfit_700Bold" },
            ]}
          >
            {t.hasCullBirds}
          </Text>
          <Text
            style={[
              styles.cullHint,
              {
                color: theme.textTertiary,
                fontFamily: "Outfit_400Regular",
              },
            ]}
          >
            {t.hasCullBirdsHint}
          </Text>
          <View style={styles.cullBtns}>
            <Pressable
              onPress={onNo}
              style={({ pressed }) => [
                styles.cullNoBtn,
                {
                  borderColor: theme.border,
                  opacity: pressed ? 0.7 : 1,
                },
              ]}
              testID="cull-no-btn"
            >
              <Text
                style={[
                  styles.cullNoBtnText,
                  {
                    color: theme.text,
                    fontFamily: "Outfit_600SemiBold",
                  },
                ]}
              >
                {t.no}
              </Text>
            </Pressable>
            <Pressable
              onPress={onYes}
              style={({ pressed }) => [
                styles.cullYesBtn,
                {
                  backgroundColor: theme.warm,
                  transform: [{ scale: pressed ? 0.97 : 1 }],
                },
              ]}
              testID="cull-yes-btn"
            >
              <MaterialCommunityIcons
                name="bird"
                size={16}
                color="#FFF"
              />
              <Text
                style={[
                  styles.cullYesBtnText,
                  { fontFamily: "Outfit_700Bold" },
                ]}
              >
                {t.yes}
              </Text>
            </Pressable>
          </View>
        </Animated.View>
      </View>
    </Modal>
  );
}

function DholtaModal({
  visible,
  totalWeight,
  totalPcs,
  rows,
  cullWeightKg,
  cullRows,
  theme,
  insets,
  onCancel,
  onSaved,
}: {
  visible: boolean;
  totalWeight: number;
  totalPcs: number;
  rows: MeasurementRow[];
  cullWeightKg: number;
  cullRows: MeasurementRow[];
  theme: ReturnType<typeof useTheme>;
  insets: { top: number; bottom: number };
  onCancel: () => void;
  onSaved: () => void;
}) {
  const { t } = useSettings();
  const [kgPerCrate, setKgPerCrate] = useState("");
  const [deductionG, setDeductionG] = useState("");
  const [pricePerKg, setPricePerKg] = useState("");
  const [fullCratesOnly, setFullCratesOnly] = useState(true);
  const [receivedAmount, setReceivedAmount] = useState("");
  const [saving, setSaving] = useState(false);

  const deductionRef = useRef<TextInput>(null);
  const priceRef = useRef<TextInput>(null);
  const receivedRef = useRef<TextInput>(null);

  useEffect(() => {
    if (visible) {
      setReceivedAmount("");
      Promise.all([
        loadLastPricePerKg(),
        loadLastKgPerCrate(),
        loadLastDeductionG(),
      ]).then(([price, kpc, dg]) => {
        if (price) setPricePerKg(price);
        if (kpc) setKgPerCrate(kpc);
        if (dg) setDeductionG(dg);
      });
    }
  }, [visible]);

  const kgPerCrateNum = parseFloat(kgPerCrate);
  const deductionGNum = parseFloat(deductionG);
  const pricePerKgNum = parseFloat(pricePerKg);

  const isValid =
    kgPerCrate.length > 0 &&
    deductionG.length > 0 &&
    pricePerKg.length > 0 &&
    !isNaN(kgPerCrateNum) &&
    kgPerCrateNum > 0 &&
    !isNaN(deductionGNum) &&
    deductionGNum >= 0 &&
    !isNaN(pricePerKgNum) &&
    pricePerKgNum > 0;

  const calc = isValid
    ? calcDholta(totalWeight, kgPerCrateNum, deductionGNum, fullCratesOnly)
    : null;

  const adjustedNetWeight =
    calc !== null ? calc.netWeight - cullWeightKg : null;

  const finalAmount =
    adjustedNetWeight !== null && pricePerKgNum > 0
      ? adjustedNetWeight * pricePerKgNum
      : null;

  const receivedAmountNum = parseFloat(receivedAmount);
  const validReceivedAmount =
    receivedAmount.length > 0 && !isNaN(receivedAmountNum) && receivedAmountNum > 0;

  const handleSave = async () => {
    if (!isValid || !calc || finalAmount === null || adjustedNetWeight === null)
      return;
    setSaving(true);

    try {
      const dholta: DholtaDetails = {
        gross_weight: totalWeight,
        kg_per_crate: kgPerCrateNum,
        deduction_per_crate_g: deductionGNum,
        full_crates_only: fullCratesOnly,
        total_crates: calc.totalCrates,
        total_deduction_kg: calc.totalDeductionKg,
        cull_weight_kg: cullWeightKg,
        net_weight: adjustedNetWeight,
        price_per_kg: pricePerKgNum,
        final_amount: finalAmount,
      };

      const totalWeightGrams = Math.round(totalWeight * 1000);
      const avgWeightKg = totalPcs > 0 ? totalWeight / totalPcs : 0;
      const avgWeightGrams = Math.round(avgWeightKg * 1000);

      const sale: SaleRecord = {
        id: Crypto.randomUUID(),
        totalWeightKg: totalWeight,
        totalWeightGrams,
        totalPcs,
        averageWeightKg: avgWeightKg,
        averageWeightGrams: avgWeightGrams,
        rows,
        cullRows: cullRows.length > 0 ? cullRows : undefined,
        createdAt: Date.now(),
        dholta,
        receivedAmount: validReceivedAmount ? receivedAmountNum : undefined,
      };

      await Promise.all([
        saveSale(sale),
        saveLastPricePerKg(pricePerKg),
        saveLastKgPerCrate(kgPerCrate),
        saveLastDeductionG(deductionG),
      ]);

      if (Platform.OS !== "web") {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
      }

      onSaved();
    } finally {
      setSaving(false);
    }
  };

  const webBottomInset = Platform.OS === "web" ? 34 : 0;

  return (
    <Modal
      visible={visible}
      animationType="slide"
      presentationStyle="pageSheet"
      onRequestClose={onCancel}
    >
      <View
        style={[styles.modalContainer, { backgroundColor: theme.background }]}
      >
        <View
          style={[
            styles.modalHeader,
            {
              backgroundColor: theme.surface,
              borderBottomColor: theme.border,
              paddingTop: insets.top + (Platform.OS === "web" ? 67 : 0) + 12,
            },
          ]}
        >
          <Pressable
            onPress={onCancel}
            hitSlop={16}
            style={({ pressed }) => [
              styles.modalCloseBtn,
              {
                backgroundColor: theme.borderLight,
                opacity: pressed ? 0.6 : 1,
              },
            ]}
          >
            <Ionicons name="close" size={20} color={theme.text} />
          </Pressable>
          <Text
            style={[
              styles.modalTitle,
              { color: theme.text, fontFamily: "Outfit_700Bold" },
            ]}
          >
            {t.tradeDeduction}
          </Text>
          <View style={{ width: 36 }} />
        </View>

        <ScrollView
          contentContainerStyle={{
            padding: 16,
            paddingBottom: insets.bottom + webBottomInset + 120,
          }}
          showsVerticalScrollIndicator={false}
          keyboardShouldPersistTaps="handled"
        >
          <View
            style={[styles.grossBanner, { backgroundColor: theme.timerBg }]}
          >
            <Text
              style={[styles.grossLabel, { fontFamily: "Outfit_400Regular" }]}
            >
              {t.grossWeight}
            </Text>
            <Text
              style={[styles.grossValue, { fontFamily: "Outfit_700Bold" }]}
            >
              {formatWeight(totalWeight)}{" "}
              <Text style={styles.grossUnit}>KG</Text>
            </Text>
            {cullWeightKg > 0 && (
              <View
                style={[
                  styles.cullBanner,
                  { backgroundColor: "rgba(255,255,255,0.12)" },
                ]}
              >
                <MaterialCommunityIcons
                  name="bird"
                  size={14}
                  color="rgba(255,255,255,0.7)"
                />
                <Text
                  style={[
                    styles.cullBannerText,
                    { fontFamily: "Outfit_500Medium" },
                  ]}
                >
                  {t.cullWeight}: {formatWeight(cullWeightKg)} KG
                </Text>
              </View>
            )}
          </View>

          <Text
            style={[
              styles.sectionLabel,
              { color: theme.textTertiary, fontFamily: "Outfit_600SemiBold" },
            ]}
          >
            {t.deductionParams}
          </Text>

          <View
            style={[
              styles.inputCard,
              {
                backgroundColor: theme.surface,
                borderColor: theme.borderLight,
              },
            ]}
          >
            <View
              style={[
                styles.inputRow,
                { borderBottomColor: theme.borderLight },
              ]}
            >
              <View style={styles.inputLabelWrap}>
                <MaterialCommunityIcons
                  name="package-variant"
                  size={16}
                  color={theme.accent}
                />
                <Text
                  style={[
                    styles.inputFieldLabel,
                    { color: theme.text, fontFamily: "Outfit_500Medium" },
                  ]}
                >
                  {t.kgPerCrate}
                </Text>
              </View>
              <TextInput
                value={kgPerCrate}
                onChangeText={setKgPerCrate}
                keyboardType="decimal-pad"
                placeholder="e.g. 20"
                placeholderTextColor={theme.textTertiary}
                returnKeyType="next"
