                style={[
                  styles.inputField,
                  {
                    color: theme.text,
                    fontFamily: "Outfit_600SemiBold",
                    borderColor: theme.border,
                    backgroundColor: theme.background,
                  },
                ]}
                testID="kg-per-crate-input"
              />
            </View>

            <View
              style={[
                styles.inputRow,
                { borderBottomColor: theme.borderLight },
              ]}
            >
              <View style={styles.inputLabelWrap}>
                <Feather name="minus-circle" size={16} color={theme.danger} />
                <Text
                  style={[
                    styles.inputFieldLabel,
                    { color: theme.text, fontFamily: "Outfit_500Medium" },
                  ]}
                >
                  {t.dholtaPerCrate}
                </Text>
              </View>
              <TextInput
                ref={deductionRef}
                value={deductionG}
                onChangeText={setDeductionG}
                keyboardType="decimal-pad"
                placeholder="e.g. 300"
                placeholderTextColor={theme.textTertiary}
                returnKeyType="next"
                onSubmitEditing={() => priceRef.current?.focus()}
                style={[
                  styles.inputField,
                  {
                    color: theme.text,
                    fontFamily: "Outfit_600SemiBold",
                    borderColor: theme.border,
                    backgroundColor: theme.background,
                  },
                ]}
                testID="deduction-g-input"
              />
            </View>

            <View style={styles.inputRow}>
              <View style={styles.inputLabelWrap}>
                <Feather name="tag" size={16} color={theme.success} />
                <Text
                  style={[
                    styles.inputFieldLabel,
                    { color: theme.text, fontFamily: "Outfit_500Medium" },
                  ]}
                >
                  {t.pricePerKg}
                </Text>
              </View>
              <TextInput
                ref={priceRef}
                value={pricePerKg}
                onChangeText={setPricePerKg}
                keyboardType="decimal-pad"
                placeholder="e.g. 250"
                placeholderTextColor={theme.textTertiary}
                returnKeyType="done"
                onSubmitEditing={Keyboard.dismiss}
                style={[
                  styles.inputField,
                  {
                    color: theme.text,
                    fontFamily: "Outfit_600SemiBold",
                    borderColor: theme.border,
                    backgroundColor: theme.background,
                  },
                ]}
                testID="price-per-kg-input"
              />
            </View>
          </View>

          <Pressable
            onPress={() => setFullCratesOnly((v) => !v)}
            style={[
              styles.checkboxRow,
              {
                backgroundColor: theme.surface,
                borderColor: fullCratesOnly ? theme.accent : theme.borderLight,
              },
            ]}
          >
            <View
              style={[
                styles.checkbox,
                {
                  borderColor: fullCratesOnly ? theme.accent : theme.border,
                  backgroundColor: fullCratesOnly
                    ? theme.accent
                    : "transparent",
                },
              ]}
            >
              {fullCratesOnly && (
                <Ionicons name="checkmark" size={14} color="#FFF" />
              )}
            </View>
            <View style={styles.checkboxTextWrap}>
              <Text
                style={[
                  styles.checkboxLabel,
                  { color: theme.text, fontFamily: "Outfit_600SemiBold" },
                ]}
              >
                {t.fullCratesOnly}
              </Text>
              <Text
                style={[
                  styles.checkboxSub,
                  {
                    color: theme.textTertiary,
                    fontFamily: "Outfit_400Regular",
                  },
                ]}
              >
                {t.fullCratesOnlyHint}
              </Text>
            </View>
          </Pressable>

          {calc && finalAmount !== null && adjustedNetWeight !== null && (
            <View
              style={[
                styles.summaryCard,
                {
                  backgroundColor: theme.surface,
                  borderColor: theme.borderLight,
                },
              ]}
            >
              <Text
                style={[
                  styles.sectionLabel,
                  {
                    color: theme.textTertiary,
                    fontFamily: "Outfit_600SemiBold",
                    marginBottom: 12,
                  },
                ]}
              >
                {t.calcSummary}
              </Text>

              <SummaryRow
                label={t.grossWeight}
                value={`${formatWeight(totalWeight)} KG`}
                theme={theme}
              />
              <SummaryRow
                label={
                  fullCratesOnly ? t.totalCratesFloored : t.totalCrates
                }
                value={
                  fullCratesOnly
                    ? `${calc.totalCrates}`
                    : `${calc.totalCrates.toFixed(3)}`
                }
                theme={theme}
              />
              <SummaryRow
                label={t.totalDeduction}
                value={`-${formatWeight(calc.totalDeductionKg)} KG`}
                theme={theme}
                isNegative
              />
              {cullWeightKg > 0 && (
                <SummaryRow
                  label={t.cullWeight}
                  value={`-${formatWeight(cullWeightKg)} KG`}
                  theme={theme}
                  isNegative
                />
