Here's the result of running `cat -n` on a snippet of metro.config.js
     1→const { getDefaultConfig } = require("expo/metro-config");
     2→const path = require("path");
     3→const fs = require("fs");
     4→
     5→const config = getDefaultConfig(__dirname);
     6→
     7→// Prevent Metro from crashing when Replit cleans up temporary files in
     8→// .local/skills (skill runner) and .local/state/workflow-logs (runner logs).
     9→config.resolver.blockList = [
    10→  /\.local[/\\]skills[/\\]/,
    11→  /\.local[/\\]state[/\\]/,
    12→];
    13→
    14→// Packages that must be deduplicated to a single instance in the app.
    15→// @clerk/clerk-js ships its own node_modules/react (19.2.5) which causes
    16→// "Invalid hook call" when mixed with the app's React (19.1.0). We force
    17→// every `require('react')` to resolve to the project-root copy.
    18→const DEDUP_MODULES = {
    19→  react: require.resolve("react"),
    20→  "react/jsx-runtime": require.resolve("react/jsx-runtime"),
    21→  "react/jsx-dev-runtime": require.resolve("react/jsx-dev-runtime"),
    22→  "react-dom": require.resolve("react-dom"),
    23→  "react-native": require.resolve("react-native"),
    24→};
    25→
    26→const originalResolveRequest = config.resolver.resolveRequest;
    27→config.resolver.resolveRequest = (context, moduleName, platform) => {
    28→  // 1. Deduplicate react and friends
    29→  if (Object.prototype.hasOwnProperty.call(DEDUP_MODULES, moduleName)) {
    30→    return { filePath: DEDUP_MODULES[moduleName], type: "sourceFile" };
    31→  }
    32→
    33→  // 2. @clerk/expo uses internal paths not listed in its package.json exports
    34→  //    map. Metro 0.83+ enforces the exports map and blocks these. Intercept
    35→  //    relative requires originating from within @clerk/expo/dist and resolve
    36→  //    them directly.
    37→  if (
    38→    context.originModulePath.includes(
    39→      path.join("node_modules", "@clerk", "expo", "dist")
    40→    )
    41→  ) {
    42→    if (moduleName.startsWith("./") || moduleName.startsWith("../")) {
    43→      const origin = path.dirname(context.originModulePath);
    44→      const candidates = [
    45→        ...(platform === "web"
    46→          ? [
    47→              path.resolve(origin, moduleName + ".web.js"),
    48→              path.resolve(origin, moduleName, "index.web.js"),
    49→            ]
    50→          : []),
    51→        path.resolve(origin, moduleName + ".js"),
    52→        path.resolve(origin, moduleName, "index.js"),
    53→      ];
    54→      for (const candidate of candidates) {
    55→        if (fs.existsSync(candidate)) {
    56→          return { filePath: candidate, type: "sourceFile" };
    57→        }
    58→      }
    59→    }
    60→  }
    61→
    62→  if (originalResolveRequest) {
    63→    return originalResolveRequest(context, moduleName, platform);
    64→  }
    65→  return context.resolveRequest(context, moduleName, platform);
    66→};
